parameters.jsCode:
const item = $input.item.json;
const raw = item.text ?? item.output ?? item.output?.[0]?.content?.[0]?.text ?? '';
const cleaned = raw.replace(/^```json\n?|^```\n?|```$/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { givenName: parsed.givenName, fullName: parsed.fullName } }];
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message + '. Raw output: ' + String(raw).substring(0, 300));
}

let results = [];
let counter = 0;

do {
  try {
    const texts = $("Receive texts")
      .all(0, counter)
      .map((item) => item.json.text);
    results = [...results, ...texts];
  } catch (error) {
    return { texts: results };
  }
  counter++;
} while (true);

